1	import { useState, useEffect, useRef } from "react";
2	import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
3	import { useAdminApi } from "@/hooks/useAdminApi";
4	import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
5	import { Button } from "@/components/ui/button";
6	import { Badge } from "@/components/ui/badge";
7	import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
8	import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
9	import { Label } from "@/components/ui/label";
10	import { Progress } from "@/components/ui/progress";
11	import { Loader2, FileText, CheckCircle2, XCircle, AlertTriangle, ChevronDown, ChevronUp, ScanLine, Sparkles, Save, Monitor, Server, ImageIcon, Play, Pause, RotateCcw, Trash2, Check, X, Clock } from "lucide-react";
12	import { toast } from "sonner";
13	
14	// ── Types ─────────────────────────────────────────────────────────────────────
15	
16	interface PdfSample {
17	  id: string;
18	  asset_id: string | null;
19	  filename: string;
20	  relative_path: string;
21	  extraction_method: "pdf_text" | "likely_scanned" | "failed" | "ocr_text" | "ai_vision";
22	  extracted_text: string | null;
23	  page_count: number | null;
24	  char_count: number;
25	  extraction_error: string | null;
26	  sampled_at: string;
27	  thumbnail_url: string | null;
28	  replacement_thumbnail_url: string | null;
29	  replacement_filename: string | null;
30	}
31	
32	interface FileProgressEntry {
33	  filename: string;
34	  status: "success" | "failed";
35	  method: string;
36	  chars: number;
37	  error?: string;
38	}
39	
40	interface ProgressInfo {
41	  processed: number;
42	  total: number;
43	  current_file: string | null;
44	  current_step: string | null;
45	  file_results: FileProgressEntry[];
46	  updated_at: string;
47	}
48	
49	// ── Step label helper ─────────────────────────────────────────────────────────
50	
51	function stepLabel(step: string | null): string {
52	  switch (step) {
53	    case "starting": return "Starting…";
54	    case "reading": return "Reading file";
55	    case "mupdf": return "mupdf text extraction";
56	    case "rendering": return "Rendering page to PNG";
57	    case "ocr": return "OCR (tesseract.js)";
58	    case "ai_vision": return "AI vision";
59	    case "done": return "Done";
60	    default: return step ?? "";
61	  }
62	}
63	
64	// ── Method badge ───────────────────────────────────────────────────────────────
65	
66	function MethodBadge({ method }: { method: PdfSample["extraction_method"] | string }) {
67	  if (method === "pdf_text") {
68	    return (
69	      <Badge className="bg-green-100 text-green-800 gap-1 text-xs">
70	        <CheckCircle2 className="h-3 w-3" /> Native text
71	      </Badge>
72	    );
73	  }
74	  if (method === "ocr_text") {
75	    return (
76	      <Badge className="bg-blue-100 text-blue-800 gap-1 text-xs">
77	        <ScanLine className="h-3 w-3" /> OCR
78	      </Badge>
79	    );
80	  }
81	  if (method === "ai_vision") {
82	    return (
83	      <Badge className="bg-purple-100 text-purple-800 gap-1 text-xs">
84	        <Sparkles className="h-3 w-3" /> AI vision
85	      </Badge>
86	    );
87	  }
88	  if (method === "likely_scanned") {
89	    return (
90	      <Badge className="bg-amber-100 text-amber-800 gap-1 text-xs">
91	        <AlertTriangle className="h-3 w-3" /> Likely scanned
92	      </Badge>
93	    );
94	  }
95	  return (
96	    <Badge className="bg-red-100 text-red-800 gap-1 text-xs">
97	      <XCircle className="h-3 w-3" /> Failed
98	    </Badge>
99	  );
100	}
101	
102	// ── Sample row ────────────────────────────────────────────────────────────────
103	
104	function SampleRow({ sample }: { sample: PdfSample }) {
105	  const [expanded, setExpanded] = useState(false);
106	
107	  return (
108	    <>
109	      <TableRow
110	        className="cursor-pointer hover:bg-muted/50"
111	        onClick={() => sample.extracted_text && setExpanded((v) => !v)}
112	      >
113	        <TableCell className="text-xs font-mono max-w-[220px] truncate" title={sample.relative_path}>
114	          {sample.filename}
115	        </TableCell>
116	        <TableCell>
117	          <MethodBadge method={sample.extraction_method} />
118	        </TableCell>
119	        <TableCell className="text-xs text-center text-muted-foreground">
120	          {sample.page_count ?? "—"}
121	        </TableCell>
122	        <TableCell className="text-xs text-center text-muted-foreground">
123	          {sample.char_count.toLocaleString()}
124	        </TableCell>
125	        <TableCell className="text-xs text-muted-foreground max-w-[300px] truncate">
126	          {sample.extraction_error
127	            ? <span className="text-red-600">{sample.extraction_error}</span>
128	            : sample.extracted_text
129	              ? sample.extracted_text.slice(0, 120).replace(/\s+/g, " ")
130	              : <span className="italic">no text</span>
131	          }
132	        </TableCell>
133	        <TableCell className="text-xs text-center">
134	          {sample.extracted_text ? (
135	            expanded ? <ChevronUp className="h-3.5 w-3.5 text-muted-foreground" /> : <ChevronDown className="h-3.5 w-3.5 text-muted-foreground" />
136	          ) : null}
137	        </TableCell>
138	      </TableRow>
139	      {expanded && sample.extracted_text && (
140	        <TableRow>
141	          <TableCell colSpan={6} className="bg-muted/30 p-3">
142	            <pre className="text-xs whitespace-pre-wrap font-mono leading-relaxed max-h-64 overflow-y-auto">
143	              {sample.extracted_text}
144	            </pre>
145	          </TableCell>
146	        </TableRow>
147	      )}
148	    </>
149	  );
150	}
151	
152	// ── Agent status badge ───────────────────────────────────────────────────────
153	
154	interface AgentStatusInfo {
155	  id: string;
156	  name: string;
157	  type: string;
158	  online: boolean;
159	  last_heartbeat_seconds_ago: number | null;
160	  last_heartbeat: string | null;
161	  healthy: boolean | null;
162	  version: string | null;
163	}
164	
165	function AgentStatusBadges({ agents, targetType }: { agents: AgentStatusInfo[]; targetType: string }) {
166	  if (agents.length === 0) {
167	    return (
168	      <div className="text-xs text-destructive bg-destructive/10 rounded px-2 py-1">
169	        ⚠ No agents registered. Deploy a Bridge Agent or Windows Agent first.
170	      </div>
171	    );
172	  }
173	
174	  return (
175	    <div className="flex flex-wrap gap-2">
176	      {agents.map((a) => {
177	        const isTarget = a.type === targetType;
178	        const agoStr = a.last_heartbeat_seconds_ago !== null
179	          ? a.last_heartbeat_seconds_ago < 60
180	            ? `${a.last_heartbeat_seconds_ago}s ago`
181	            : `${Math.round(a.last_heartbeat_seconds_ago / 60)}m ago`
182	          : "never";
183	
184	        return (
185	          <div
186	            key={a.id}
187	            className={`flex items-center gap-1.5 text-xs rounded px-2 py-1 border ${
188	              a.online
189	                ? "border-green-300 bg-green-50 text-green-800"
190	                : "border-red-300 bg-red-50 text-red-800"
191	            }`}
192	          >
193	            {a.type === "windows-render" ? <Monitor className="h-3 w-3" /> : <Server className="h-3 w-3" />}
194	            <span className="font-medium">{a.name}</span>
195	            <span className={`inline-block h-1.5 w-1.5 rounded-full ${a.online ? "bg-green-500" : "bg-red-500"}`} />
196	            <span className="text-muted-foreground">({agoStr})</span>
197	            {isTarget && (
198	              <Badge variant="outline" className="text-[10px] px-1 py-0 h-4">target</Badge>
199	            )}
200	            {a.version && <span className="text-muted-foreground text-[10px]">v{a.version}</span>}
201	          </div>
202	        );
203	      })}
204	    </div>
205	  );
206	}
207	
208	// ── Live progress panel ──────────────────────────────────────────────────────
209	
210	function LiveProgressPanel({ request, agentStatuses, targetAgentType }: {
211	  request: Record<string, unknown>;
212	  agentStatuses: AgentStatusInfo[];
213	  targetAgentType: string;
214	}) {
215	  const [nowMs, setNowMs] = useState(() => Date.now());
216	
217	  useEffect(() => {
218	    const interval = setInterval(() => setNowMs(Date.now()), 1000);
219	    return () => clearInterval(interval);
220	  }, []);
221	
222	  const status = request.status as string;
223	  const agentName = (request.claimed_by_agent_name as string) ?? null;
224	  const progress = request.progress as ProgressInfo | undefined;
225	  const requestedAt = request.requested_at as string | undefined;
226	  const errorMsg = request.error as string | undefined;
227	
228	  const isProcessing = status === "processing";
229	  const isPending = status === "pending";
230	  const isError = status === "error";
231	
232	  const processed = progress?.processed ?? 0;
233	  const total = progress?.total ?? 0;
234	  const pct = total > 0 ? Math.round((processed / total) * 100) : 0;
235	  const currentFile = progress?.current_file ?? null;
236	  const currentStep = progress?.current_step ?? null;
237	  const fileResults = progress?.file_results ?? [];
238	
239	  // Time since requested
240	  const elapsed = requestedAt
241	    ? Math.round((nowMs - new Date(requestedAt).getTime()) / 1000)
242	    : 0;
243	  const elapsedStr = elapsed > 60
244	    ? `${Math.floor(elapsed / 60)}m ${elapsed % 60}s`
245	    : `${elapsed}s`;
246	
247	  // Check if target agents are online
248	  const targetAgents = agentStatuses.filter((a) => a.type === targetAgentType);
249	  const anyTargetOnline = targetAgents.some((a) => a.online);
250	
251	  return (
252	    <div className="mt-3 space-y-3">
253	      {/* Agent connectivity status */}
254	      <AgentStatusBadges agents={agentStatuses} targetType={targetAgentType} />
255	
256	      {/* Status line */}
257	      <div className="flex items-center gap-3 text-sm">
258	        {isPending && !agentName && (
259	          <>
260	            <Loader2 className="h-4 w-4 animate-spin text-amber-500" />
261	            <div className="space-y-0.5">
262	              <span className="text-amber-600">
263	                Waiting for {targetAgentType === "windows-render" ? "Windows" : "Bridge"} agent to claim… ({elapsedStr})
264	              </span>
265	              {!anyTargetOnline && targetAgents.length > 0 && (
266	                <p className="text-xs text-destructive">
267	                  ⚠ Target agent{targetAgents.length > 1 ? "s" : ""} ({targetAgents.map((a) => a.name).join(", ")}) {targetAgents.length > 1 ? "are" : "is"} OFFLINE.
268	                  {" "}Request will auto-timeout at 3 minutes.
269	                </p>
270	              )}
271	              {targetAgents.length === 0 && (
272	                <p className="text-xs text-destructive">
273	                  ⚠ No {targetAgentType} agents registered. This request cannot be claimed. Will auto-timeout at 3 minutes.
274	                </p>
275	              )}
276	            </div>
277	          </>
278	        )}
279	        {(isProcessing || (isPending && agentName)) && (
280	          <>
281	            <Loader2 className="h-4 w-4 animate-spin text-primary" />
282	            <span className="text-foreground">
283	              Processing on{" "}
284	              <span className="font-medium inline-flex items-center gap-1">
285	                {agentName?.toLowerCase().includes("windows") ? (
286	                  <><Monitor className="h-3.5 w-3.5" /> {agentName}</>
287	                ) : (
288	                  <><Server className="h-3.5 w-3.5" /> {agentName ?? "agent"}</>
289	                )}
290	              </span>
291	              <span className="text-muted-foreground ml-2">({elapsedStr})</span>
292	            </span>
293	          </>
294	        )}
295	        {isError && (
296	          <div className="space-y-1">
297	            <div className="flex items-center gap-2">
298	              <XCircle className="h-4 w-4 text-destructive flex-shrink-0" />
299	              <span className="text-destructive font-medium">Failed</span>
300	            </div>
301	            <p className="text-xs text-destructive/90 bg-destructive/5 rounded p-2 font-mono whitespace-pre-wrap">
302	              {errorMsg ?? "Unknown error"}
303	            </p>
304	          </div>
305	        )}
306	      </div>
307	
308	      {/* Progress bar */}
309	      {total > 0 && (
310	        <div className="space-y-1">
311	          <div className="flex items-center justify-between text-xs text-muted-foreground">
312	            <span>{processed} / {total} PDFs</span>
313	            <span>{pct}%</span>
314	          </div>
315	          <Progress value={pct} className="h-2" />
316	        </div>
317	      )}
318	
319	      {/* Current file + step */}
320	      {currentFile && currentStep && currentStep !== "done" && (
321	        <p className="text-xs text-muted-foreground">
322	          <span className="font-mono">{currentFile}</span>
323	          {" — "}
324	          <span className="italic">{stepLabel(currentStep)}</span>
325	        </p>
326	      )}
327	
328	      {/* Live file results */}
329	      {fileResults.length > 0 && (
330	        <div className="border rounded-md overflow-hidden">
331	          <Table>
332	            <TableHeader>
333	              <TableRow>
334	                <TableHead className="text-xs py-1">File</TableHead>
335	                <TableHead className="text-xs py-1">Result</TableHead>
336	                <TableHead className="text-xs py-1 text-center">Chars</TableHead>
337	                <TableHead className="text-xs py-1">Error</TableHead>
338	              </TableRow>
339	            </TableHeader>
340	            <TableBody>
341	              {fileResults.map((fr, i) => (
342	                <TableRow key={i}>
343	                  <TableCell className="text-xs font-mono py-1 max-w-[200px] truncate">
344	                    {fr.filename}
345	                  </TableCell>
346	                  <TableCell className="py-1">
347	                    <MethodBadge method={fr.method} />
348	                  </TableCell>
349	                  <TableCell className="text-xs text-center py-1 text-muted-foreground">
350	                    {fr.chars.toLocaleString()}
351	                  </TableCell>
352	                  <TableCell className="text-xs py-1 text-red-600 max-w-[200px] truncate">
353	                    {fr.error ?? "—"}
354	                  </TableCell>
355	                </TableRow>
356	              ))}
357	            </TableBody>
358	          </Table>
359	        </div>
360	      )}
361	    </div>
362	  );
363	}
364	
365	interface OpenRouterModel {
366	  id: string;
367	  name: string;
368	  context_length: number | null;
369	}
370	
371	// ── AI vision model config card ───────────────────────────────────────────────
372	
373	function AiVisionConfigCard() {
374	  const { call } = useAdminApi();
375	  const queryClient = useQueryClient();
376	
377	  // Fetch vision models live from OpenRouter and saved selection in parallel
378	  const { data: modelsData, isLoading: modelsLoading, error: modelsError } = useQuery({
379	    queryKey: ["openrouter-vision-models"],
380	    queryFn: () => call("get-openrouter-vision-models"),
381	    staleTime: 5 * 60_000,
382	  });
383	
384	  const { data: configData } = useQuery({
385	    queryKey: ["admin-config", "PDF_EXTRACTION_CONFIG"],
386	    queryFn: () => call("get-config", { keys: ["PDF_EXTRACTION_CONFIG"] }),
387	  });
388	
389	  const visionModels: OpenRouterModel[] = (modelsData?.models ?? []) as OpenRouterModel[];
390	
391	  const savedModelId: string = (() => {
392	    const raw = configData?.config?.PDF_EXTRACTION_CONFIG?.value ?? configData?.config?.PDF_EXTRACTION_CONFIG;
393	    return (raw as Record<string, string> | null)?.ai_vision_model_id ?? "";
394	  })();
395	
396	  const [selectedModelId, setSelectedModelId] = useState("");
397	  const [loaded, setLoaded] = useState(false);
398	
399	  useEffect(() => {
400	    if (savedModelId && !loaded) {
401	      setSelectedModelId(savedModelId);
402	      setLoaded(true);
403	    }
404	  }, [savedModelId, loaded]);
405	
406	  const saveMutation = useMutation({
407	    mutationFn: () =>
408	      call("set-config", { entries: { PDF_EXTRACTION_CONFIG: { ai_vision_model_id: selectedModelId } } }),
409	    onSuccess: () => {
410	      toast.success("AI vision model saved — takes effect on next PDF sample run");
411	      queryClient.invalidateQueries({ queryKey: ["admin-config", "PDF_EXTRACTION_CONFIG"] });
412	      setLoaded(false);
413	    },
414	    onError: (e: Error) => toast.error(e.message || "Failed to save"),
415	  });
416	
417	  const isDirty = selectedModelId !== savedModelId;
418	
419	  return (
420	    <Card>
421	      <CardHeader className="pb-3">
422	        <CardTitle className="text-base flex items-center gap-2">
423	          <Sparkles className="h-4 w-4" />
424	          AI Vision Model
425	        </CardTitle>
426	      </CardHeader>
427	      <CardContent className="space-y-3">
428	        <p className="text-sm text-muted-foreground">
429	          Used as the final fallback when mupdf text extraction and OCR both fail (e.g. scanned PDFs with no machine-readable text).
430	          Sourced live from OpenRouter — all models that accept image input are shown.
431	        </p>
432	        {modelsLoading && (
433	          <div className="flex items-center gap-2 text-xs text-muted-foreground">
434	            <Loader2 className="h-3.5 w-3.5 animate-spin" /> Loading models from OpenRouter…
435	          </div>
436	        )}
437	        {modelsError && (
438	          <p className="text-sm text-destructive">
439	            Could not load models from OpenRouter: {(modelsError as Error).message}
440	          </p>
441	        )}
442	        {!modelsLoading && !modelsError && visionModels.length === 0 && (
443	          <p className="text-sm text-amber-600">
444	            No vision models returned. Check that <code className="text-xs">OPENROUTER_API_KEY</code> is set in admin_config.
445	          </p>
446	        )}
447	        {visionModels.length > 0 && (
448	          <div className="flex items-end gap-3">
449	            <div className="flex-1 space-y-1.5">
450	              <Label className="text-xs">Vision model ({visionModels.length} available)</Label>
451	              <Select value={selectedModelId} onValueChange={setSelectedModelId}>
452	                <SelectTrigger className="h-8 text-xs">
453	                  <SelectValue placeholder="Select a vision model…" />
454	                </SelectTrigger>
455	                <SelectContent className="max-h-72">
456	                  {visionModels.map((m) => (
457	                    <SelectItem key={m.id} value={m.id} className="text-xs">
458	                      {m.name}
459	                      <span className="ml-2 text-muted-foreground text-[10px]">{m.id}</span>
460	                    </SelectItem>
461	                  ))}
462	                </SelectContent>
463	              </Select>
464	            </div>
465	            <Button
466	              size="sm"
467	              disabled={!isDirty || !selectedModelId || saveMutation.isPending}
468	              onClick={() => saveMutation.mutate()}
469	              className="h-8"
470	            >
471	              {saveMutation.isPending ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <><Save className="h-3.5 w-3.5 mr-1.5" />Save</>}
472	            </Button>
473	          </div>
474	        )}
475	      </CardContent>
476	    </Card>
477	  );
478	}
479	
480	// ── .ai / .pdf Duplicates Card ────────────────────────────────────────────────
481	
482	interface AiDuplicate {
483	  id: string;
484	  filename: string;
485	  relative_path: string;
486	  has_thumbnail: boolean;
487	}
488	
489	function AiDuplicatesCard() {
490	  const { call } = useAdminApi();
491	  const queryClient = useQueryClient();
492	  const [preview, setPreview] = useState<AiDuplicate[] | null>(null);
493	  const [confirming, setConfirming] = useState(false);
494	
495	  const findMutation = useMutation({
496	    mutationFn: () => call("find-ai-pdf-duplicates"),
497	    onSuccess: (res) => {
498	      const r = res as { count: number; duplicates: AiDuplicate[] };
499	      setPreview(r.duplicates);
500	      if (r.count === 0) toast.success("No .ai/.pdf duplicates found");
501	    },
502	    onError: (e) => toast.error(`Failed: ${(e as Error).message}`),
503	  });
504	
505	  const deleteMutation = useMutation({
506	    mutationFn: () => call("delete-ai-pdf-duplicates"),
507	    onSuccess: (res) => {
508	      const r = res as { deleted: number; thumbnails_deleted: number; message: string };
509	      toast.success(r.message);
510	      setPreview(null);
511	      setConfirming(false);
512	      queryClient.invalidateQueries({ queryKey: ["pdf-text-samples"] });
513	    },
514	    onError: (e) => {
515	      toast.error(`Delete failed: ${(e as Error).message}`);
516	      setConfirming(false);
517	    },
518	  });
519	
520	  return (
521	    <Card>
522	      <CardHeader className="pb-3">
523	        <div className="flex items-center justify-between">
524	          <CardTitle className="text-base flex items-center gap-2">
525	            <Trash2 className="h-4 w-4" />
526	            .ai / .pdf Duplicate Cleanup
527	          </CardTitle>
528	          <div className="flex items-center gap-2">
529	            {preview && preview.length > 0 && !confirming && (
530	              <Button
531	                size="sm"
532	                variant="destructive"
533	                onClick={() => setConfirming(true)}
534	                disabled={deleteMutation.isPending}
535	              >
536	                <Trash2 className="mr-1.5 h-3.5 w-3.5" />
537	                Delete {preview.length} .ai files
538	              </Button>
539	            )}
540	            {confirming && (
541	              <>
542	                <span className="text-sm text-destructive font-medium">Are you sure?</span>
543	                <Button
544	                  size="sm"
545	                  variant="destructive"
546	                  onClick={() => deleteMutation.mutate()}
547	                  disabled={deleteMutation.isPending}
548	                >
549	                  {deleteMutation.isPending ? <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" /> : "Yes, delete"}
550	                </Button>
551	                <Button size="sm" variant="outline" onClick={() => setConfirming(false)} disabled={deleteMutation.isPending}>
552	                  Cancel
553	                </Button>
554	              </>
555	            )}
556	            {!confirming && (
557	              <Button
558	                size="sm"
559	                variant="outline"
560	                onClick={() => findMutation.mutate()}
561	                disabled={findMutation.isPending || deleteMutation.isPending}
562	              >
563	                {findMutation.isPending ? <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" /> : "Find Duplicates"}
564	              </Button>
565	            )}
566	          </div>
567	        </div>
568	      </CardHeader>
569	      <CardContent className="space-y-3">
570	        <p className="text-sm text-muted-foreground">
571	          Finds .ai files that have a matching .pdf in the same folder (same base filename, different extension).
572	          The .ai is the source file; the .pdf is the distributable. Deletes the .ai asset record and its thumbnail from DO Spaces.
573	        </p>
574	        {preview !== null && preview.length === 0 && (
