974	function PdfBackfillCard() {
975	  const { call } = useAdminApi();
976	  const queryClient = useQueryClient();
977	  const [nowMs, setNowMs] = useState(() => Date.now());
978	
979	  useEffect(() => {
980	    const interval = setInterval(() => setNowMs(Date.now()), 1000);
981	    return () => clearInterval(interval);
982	  }, []);
983	
984	  const { data } = useQuery({
985	    queryKey: ["pdf-backfill-status"],
986	    queryFn: () => call("get-pdf-backfill-status"),
987	    refetchInterval: (query) => {
988	      const bf = query.state.data?.backfill as Record<string, unknown> | null;
989	      return bf?.status === "running" ? 3000 : 15000;
990	    },
991	  });
992	
993	  const triggerMutation = useMutation({
994	    mutationFn: () => call("trigger-pdf-backfill"),
995	    onSuccess: (res) => {
996	      const r = res as Record<string, unknown>;
997	      toast.success(`Backfill started — ${(r.total as number).toLocaleString()} PDFs queued`);
998	      queryClient.invalidateQueries({ queryKey: ["pdf-backfill-status"] });
999	    },
1000	    onError: (e) => toast.error(`Failed: ${(e as Error).message}`),
1001	  });
1002	
1003	  const pauseMutation = useMutation({
1004	    mutationFn: () => call("pause-pdf-backfill"),
1005	    onSuccess: () => {
1006	      toast.success("Backfill paused");
1007	      queryClient.invalidateQueries({ queryKey: ["pdf-backfill-status"] });
1008	    },
1009	    onError: (e) => toast.error(`Failed: ${(e as Error).message}`),
1010	  });
1011	
1012	  const resumeMutation = useMutation({
1013	    mutationFn: () => call("resume-pdf-backfill"),
1014	    onSuccess: () => {
1015	      toast.success("Backfill resumed");
1016	      queryClient.invalidateQueries({ queryKey: ["pdf-backfill-status"] });
1017	    },
1018	    onError: (e) => toast.error(`Failed: ${(e as Error).message}`),
1019	  });
1020	
1021	  const bf = data?.backfill as Record<string, unknown> | null;
1022	  const status = (bf?.status as string) ?? "idle";
1023	  const total = (bf?.total as number) ?? 0;
1024	  const processed = (bf?.live_processed as number) ?? (bf?.processed as number) ?? 0;
1025	  const currentFile = bf?.live_current_file as string | null;
1026	  const percent = total > 0 ? Math.min(100, Math.round((processed / total) * 100)) : 0;
1027	  const startedAt = bf?.started_at ? new Date(bf.started_at as string).getTime() : null;
1028	  const elapsedSec = startedAt ? Math.floor((nowMs - startedAt) / 1000) : 0;
1029	  const elapsedStr = elapsedSec < 60
1030	    ? `${elapsedSec}s`
1031	    : elapsedSec < 3600
1032	      ? `${Math.floor(elapsedSec / 60)}m ${elapsedSec % 60}s`
1033	      : `${Math.floor(elapsedSec / 3600)}h ${Math.floor((elapsedSec % 3600) / 60)}m`;
1034	
1035	  // Estimated time remaining
1036	  const etaStr = (() => {
1037	    if (status !== "running" || processed === 0 || !startedAt) return null;
1038	    const rate = processed / ((nowMs - startedAt) / 1000); // files/sec
1039	    if (rate <= 0) return null;
1040	    const remainSec = Math.round((total - processed) / rate);
1041	    if (remainSec < 60) return `~${remainSec}s`;
1042	    if (remainSec < 3600) return `~${Math.floor(remainSec / 60)}m`;
1043	    return `~${Math.floor(remainSec / 3600)}h ${Math.floor((remainSec % 3600) / 60)}m`;
1044	  })();
1045	
1046	  const statusBadge = (() => {
1047	    switch (status) {
1048	      case "running": return <Badge className="bg-blue-100 text-blue-800 gap-1"><Loader2 className="h-3 w-3 animate-spin" /> Running</Badge>;
1049	      case "paused": return <Badge className="bg-amber-100 text-amber-800 gap-1"><Pause className="h-3 w-3" /> Paused</Badge>;
1050	      case "completed": return <Badge className="bg-green-100 text-green-800 gap-1"><CheckCircle2 className="h-3 w-3" /> Completed</Badge>;
1051	      case "error": return <Badge className="bg-red-100 text-red-800 gap-1"><XCircle className="h-3 w-3" /> Error</Badge>;
1052	      default: return <Badge variant="outline" className="text-muted-foreground">Idle</Badge>;
1053	    }
1054	  })();
1055	
1056	  return (
1057	    <Card>
1058	      <CardHeader className="pb-3">
