2	 * Cloud API client — all outbound HTTPS calls to agent-api edge function.
3	 * No inbound networking required per PROJECT_BIBLE §2.
4	 */
5	
6	import { config } from "./config.js";
7	import { logger } from "./logger.js";
8	
9	async function callApi(action: string, payload: Record<string, unknown> = {}, timeoutMs = 30_000): Promise<Record<string, unknown>> {
10	  const body = JSON.stringify({ action, ...payload });
11	  const maxAttempts = 5;
12	  let lastError: Error | null = null;
13	
14	  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
15	    try {
16	      const res = await fetch(config.agentApiUrl, {
17	        method: "POST",
18	        headers: {
19	          "Content-Type": "application/json",
20	          "x-agent-key": config.agentKey,
21	        },
22	        body,
23	        signal: AbortSignal.timeout(timeoutMs), // hard timeout per request — prevents hung connections stalling the scan
24	      });
25	
26	      if (!res.ok) {
27	        const text = await res.text();
28	        // Don't retry client errors (4xx) — they are permanent
29	        if (res.status >= 400 && res.status < 500) {
30	          throw new Error(`agent-api ${action} returned ${res.status}: ${text}`);
31	        }
32	        // Retry server errors (5xx)
33	        lastError = new Error(`agent-api ${action} returned ${res.status}: ${text}`);
34	        if (attempt < maxAttempts) {
35	          const delay = Math.min(5000, 1000 * Math.pow(2, attempt - 1));
36	          logger.warn(`agent-api ${action} returned ${res.status}, retrying in ${delay}ms (attempt ${attempt}/${maxAttempts})`);
37	          await new Promise( r => setTimeout(r, delay));
38	          continue;
39	        }
40	        throw lastError;
41	      }
42	
43	      const data = await res.json();
44	      if (data && !data.ok) {
45	        throw new Error(`agent-api ${action} error: ${data.error || "unknown"}`);
46	      }
47	      return data;
48	
49	    } catch (e) {
50	      // Re-throw already-formatted errors (4xx or data.ok === false)
51	      if (e instanceof Error && e.message.startsWith("agent-api")) throw e;
52	      // Network error — retry
53	      lastError = e as Error;
54	      if (attempt < maxAttempts) {
55	        const delay = Math.min(5000, 1000 * Math.pow(2, attempt - 1));
56	        logger.warn(`agent-api ${action} network error, retrying in ${delay}ms (attempt ${attempt}/${maxAttempts})`, { error: (e as Error).message });
57	        await new Promise( r => setTimeout(r, delay));
58	      }
59	    }
60	  }
61	  throw lastError ?? new Error(`agent-api ${action} failed after ${maxAttempts} attempts`);
62	}
